Implement flexible authentication handlers supporting password and public key authentication methods.

## Implementation Details

### Authentication Trait
```rust
use async_trait::async_trait;
use russh_keys::key::PublicKey;

#[async_trait]
pub trait AuthHandler: Send + Sync + 'static {
    /// Authenticate with password
    async fn auth_password(&self, ctx: &AuthContext, password: &str) -> AuthResult;

    /// Authenticate with public key
    async fn auth_publickey(&self, ctx: &AuthContext, key: &PublicKey) -> AuthResult;

    /// Optional: keyboard-interactive authentication
    async fn auth_keyboard_interactive(
        &self,
        ctx: &AuthContext,
        response: &str,
    ) -> AuthResult {
        AuthResult::Reject
    }
}

pub struct AuthContext {
    pub username: String,
    pub remote_addr: SocketAddr,
    pub session_id: SessionId,
}

pub enum AuthResult {
    Accept,
    Reject,
    Partial { next_methods: Vec<AuthMethod> },
}
```

### Built-in Handlers
```rust
/// Always accepts any authentication (for development/testing)
pub struct AcceptAllAuth;

#[async_trait]
impl AuthHandler for AcceptAllAuth {
    async fn auth_password(&self, ctx: &AuthContext, _password: &str) -> AuthResult {
        log::warn!("AcceptAllAuth: accepting password auth for {}", ctx.username);
        AuthResult::Accept
    }

    async fn auth_publickey(&self, ctx: &AuthContext, _key: &PublicKey) -> AuthResult {
        log::warn!("AcceptAllAuth: accepting pubkey auth for {}", ctx.username);
        AuthResult::Accept
    }
}

/// Authorized keys file-based authentication
pub struct AuthorizedKeysAuth {
    keys_path: PathBuf,
    cache: RwLock<HashMap<String, Vec<PublicKey>>>,
}

impl AuthorizedKeysAuth {
    pub fn new(keys_path: impl Into<PathBuf>) -> Self;
    pub async fn reload(&self) -> Result<(), WishError>;
}

/// Callback-based authentication
pub struct CallbackAuth<F> {
    callback: F,
}

impl<F> CallbackAuth<F>
where
    F: Fn(&str, &str) -> bool + Send + Sync + 'static,
{
    pub fn new(callback: F) -> Self;
}
```

### Integration with russh Handler
```rust
impl Handler for ConnectionHandler {
    async fn auth_password(&mut self, user: &str, password: &str) -> Result<Auth, Self::Error> {
        let ctx = AuthContext {
            username: user.to_string(),
            remote_addr: self.remote_addr,
            session_id: self.session_id,
        };

        log::debug!("Password auth attempt for user '{}' from {}", user, self.remote_addr);

        match self.auth_handler.auth_password(&ctx, password).await {
            AuthResult::Accept => {
                log::info!("Password auth accepted for '{}'", user);
                Ok(Auth::Accept)
            }
            AuthResult::Reject => {
                log::info!("Password auth rejected for '{}'", user);
                Ok(Auth::Reject { proceed_with_methods: None })
            }
            AuthResult::Partial { next_methods } => {
                Ok(Auth::Reject { proceed_with_methods: Some(next_methods) })
            }
        }
    }
}
```

