charmed_rust-dnt: [PropTest] Property-based testing for input parsing

## Objective
Implement comprehensive property-based tests for mouse event parsing using proptest, ensuring the mouse parser correctly handles all mouse tracking modes and gracefully handles malformed input.

## Detailed Requirements

### 1. SGR Mouse Parsing Properties

```rust
use proptest::prelude::*;
use crate::mouse::{MouseEvent, MouseButton, MouseParser};
use crate::proptest::generators::mouse::*;

proptest! {
    /// Property: Valid SGR sequences parse to mouse events
    #[test]
    fn sgr_sequences_parse_correctly(
        event in arb_sgr_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let result = MouseParser::parse(&bytes);

        prop_assert!(result.is_some(), "SGR sequence should parse: {:?}", bytes);
        let (parsed, consumed) = result.unwrap();
        prop_assert_eq!(consumed, bytes.len(), "Should consume all bytes");
    }

    /// Property: SGR coordinates are preserved
    #[test]
    fn sgr_preserves_coordinates(
        event in arb_sgr_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let result = MouseParser::parse(&bytes);

        let (parsed, _) = result.unwrap();
        prop_assert_eq!(parsed.x, event.x, "X coordinate mismatch");
        prop_assert_eq!(parsed.y, event.y, "Y coordinate mismatch");
    }

    /// Property: SGR button is correctly identified
    #[test]
    fn sgr_identifies_button(
        event in arb_sgr_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert_eq!(parsed.button, event.button, "Button mismatch");
    }

    /// Property: SGR press/release is distinguished
    #[test]
    fn sgr_distinguishes_press_release(
        event in arb_sgr_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert_eq!(
            parsed.is_release(),
            !event.pressed,
            "Press/release mismatch"
        );
    }

    /// Property: SGR modifiers are preserved
    #[test]
    fn sgr_preserves_modifiers(
        event in arb_sgr_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert_eq!(parsed.shift, event.modifiers.shift);
        prop_assert_eq!(parsed.alt, event.modifiers.alt);
        prop_assert_eq!(parsed.ctrl, event.modifiers.ctrl);
    }
}
```

### 2. X10 Mouse Parsing Properties

```rust
proptest! {
    /// Property: Valid X10 sequences parse correctly
    #[test]
    fn x10_sequences_parse_correctly(
        event in arb_x10_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let result = MouseParser::parse(&bytes);

        prop_assert!(result.is_some(), "X10 sequence should parse");
        let (_, consumed) = result.unwrap();
        prop_assert_eq!(consumed, 6, "X10 is always 6 bytes");  // ESC [ M Cb Cx Cy
    }

    /// Property: X10 coordinates are correctly decoded (+32 offset)
    #[test]
    fn x10_decodes_coordinates(
        event in arb_x10_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert_eq!(parsed.x, event.x as u16, "X coordinate mismatch");
        prop_assert_eq!(parsed.y, event.y as u16, "Y coordinate mismatch");
    }

    /// Property: X10 button is correctly identified
    #[test]
    fn x10_identifies_button(
        event in arb_x10_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert_eq!(parsed.button, event.button);
    }

    /// Property: X10 coordinate limits are enforced
    #[test]
    fn x10_respects_coordinate_limits(
        x in 1u8..=223,
        y in 1u8..=223,
    ) {
        let event = X10MouseEvent {
            button: MouseButton::Left,
            x, y,
        };
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert!(parsed.x <= 223);
        prop_assert!(parsed.y <= 223);
    }
}
```

