### 4. Wheel Event Properties

```rust
proptest! {
    /// Property: Wheel events are correctly identified
    #[test]
    fn wheel_events_parse(
        direction in prop_oneof![
            Just(MouseButton::WheelUp),
            Just(MouseButton::WheelDown),
            Just(MouseButton::WheelLeft),
            Just(MouseButton::WheelRight),
        ],
        x in 1u16..=1000,
        y in 1u16..=1000,
    ) {
        let event = SgrMouseEvent {
            button: direction,
            modifiers: MouseModifiers::default(),
            x, y,
            pressed: true,
            motion: false,
        };
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert!(parsed.is_wheel());
        prop_assert_eq!(parsed.button, direction);
    }

    /// Property: Wheel direction is preserved
    #[test]
    fn wheel_direction_preserved(
        up in any::<bool>(),
        x in 1u16..=1000,
        y in 1u16..=1000,
    ) {
        let button = if up { MouseButton::WheelUp } else { MouseButton::WheelDown };
        let event = SgrMouseEvent {
            button,
            modifiers: MouseModifiers::default(),
            x, y,
            pressed: true,
            motion: false,
        };
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();

        prop_assert_eq!(parsed.wheel_delta_y(), if up { -1 } else { 1 });
    }
}
```

